var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"22:25 ARC-KP1 \\n헤비암즈 대표의 사무실","JPN":"22:25 ARC-KP1 \\nヘビーアームズ代表のオフィス","ENG":"22:25 ARC-KP1\\nHeavyarms CEO’s office","TWN":"22:25 ARC-KP1 \\n重武裝代表辦公室"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"……고모?","JPN":"……叔母さん？","ENG":"...Auntie?","TWN":"……姑姑？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"고모! 뭐라도 말 좀 해 봐요!","JPN":"叔母さん！　答えてください！","ENG":"Auntie! Say something!","TWN":"姑姑！你說句話啊！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"이런 젠장할!!","JPN":"くそっ！！","ENG":"Crap!!","TWN":"該死的！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"겨우 한 번 실패한 것 가지고 날 손절해?","JPN":"たった一度失敗したからって、俺を捨て駒にする気か？","ENG":"You dare cut me off after just one tiny mistake?!","TWN":"因為失敗一次，就要和我切割乾淨？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"애초에 나한테 접근할 때부터 뭔가 이상했어……. 얼굴도 안 보이는 녀석을 믿으면 안 됐는데!!","JPN":"そもそも俺に近づいてきた時から怪しかったんだ……\\n顔も見せないやつを信じるんじゃなかった！","ENG":"I should’ve known something was up from the start... How could I have trusted someone that I’ve never even met!!","TWN":"打從一開始你接近我的時候，我就覺得奇怪……果然不該相信從未露過臉的傢伙！！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"젠장!! 이게 다 너 때문이야! 이 빌어먹을 모조품아!","JPN":"ちくしょう！！　全部お前のせいだ！　この使えない模造品が！","ENG":"Aargh!! This is all your fault! You lousy knock-off!","TWN":"該死！！都怪你不好！你這個該死的山寨版！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"그 괴물 같은 계집애는 뭐든! 뭐든! 뭐든 잘한다고!!","JPN":"あの化け物みたいな小娘はなんでも！　なんでもできるんだよ！！","ENG":"That monster! Can! Do! Everything well!!","TWN":"那個怪物每件事！每件事！每件事！都很厲害！！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"넌 그 괴물이랑 똑같은 거라면서 왜 시키는 일 하나 제대로 못하는데!","JPN":"お前はあの化け物と同じはずなのに、\\nなぜ任せた仕事をまともにできねえんだよ！","ENG":"But you! You’re the same as that monster, but why can’t you do anything right?!","TWN":"你和那個怪物長得一模一樣，為什麼連一件事都辦不好！！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"변명이라도 해 봐! 이 망할 짝퉁아! 너까지 날 무시해!?","JPN":"言い訳でもしてみろ！　この偽物め！　お前まで俺を無視するのかよ！？","ENG":"Well, say something! You lousy piece of junk! Oh, you think you’re better than me now, huh?!","TWN":"你說話啊！該死的山寨版！連你也瞧不起我是嗎？！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"젠장……. 젠장, 이러고 있을 때가 아냐.","JPN":"くそ……こうしている場合じゃない。","ENG":"Damn it... Damn it! I don’t have time for this.","TWN":"可惡……該死！我不能坐以待斃！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"감찰과랑 도시관리국이 그 괴물 계집애에게 매달리고 있을 때 여길 떠야 돼.","JPN":"監察課と都市管理局があの化け物を追っている隙に、\\nここを離れないと。","ENG":"I need to get out of here while City Managements and Investigations are still searching for that monster!","TWN":"趁著監察科和城市管理局纏著那個怪物，我得趕快離開這裡！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"여권, 그렇지. 먼저 여권부터…….","JPN":"パスポート。そうだ、まずはパスポートを……","ENG":"Passport... Yes. I need to get my passport and...","TWN":"護照！對！先找護照……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"어? 이게 무슨 소리야?","JPN":"うん？　なんの音だ？","ENG":"Huh? What was that?","TWN":"嗯？這是什麼聲音？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"뭐, 뭐야? 왜 문이 멋대로 열려?","JPN":"な、なんだ！　なんで扉が勝手に開くんだ！？","ENG":"W-what? Why did the door suddenly open?","TWN":"怎麼搞的？門怎麼會打開？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"안녕하세요, 재혁 오라버니.","JPN":"こんにちは、タツヤお兄様。","ENG":"Hello, Jaehyuk.","TWN":"大哥，是我。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"뭐, 뭐, 뭐, 뭐, 뭐야!! 너 여기 어떻게 알고 들어왔어!?","JPN":"な、な、な、な、なんだ！！　なんでお前がここにいるんだ！？","ENG":"W-what?!! How did you get in here?!","TWN":"什…什…什…什麼！！你怎麼會知道這個地方，而且還闖進來？！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 그냥 평범하게 문을 열고 들어온 건데요?","JPN":"はい？　ただ、普通に扉を開けて入ってきただけですよ？","ENG":"Hmm? I just opened the door and walked in.","TWN":"嗯？不就是把門打開後進來嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그보다 지금이라도 자수하세요, 재혁 오라버니.","JPN":"それより、今からでも間に合います。自首してください、タツヤお兄様。","ENG":"Jaehyuk, you need to turn yourself in.","TWN":"大哥，現在還來得及，你自首吧！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님께서 가르쳐 주셨어요. 때로는 자기 잘못을 받아들이고 인정할 줄 알아야 한다고.","JPN":"お祖父様が教えてくださいました。\\n時には自分の過ちを受け入れ、認めなければならないと。","ENG":"Grandfather taught me that you must learn to accept and admit your mistakes.","TWN":"爺爺有說，有時候也要懂得承認自己的錯誤。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"하…….","JPN":"は……","ENG":"Ha…","TWN":"哈……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"뭐? 자수? 웃기고 있네!","JPN":"はあ？　自首？　ふざけるな！","ENG":"Turn myself in? You got to be joking!","TWN":"你說什麼？自首？你要笑死我！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"내가 뭘 자수해야 하는데? 어? 뭘 자수해야 하냐고!!","JPN":"俺は何を自首すればいいんだ？　なあ？　俺に何の罪があるって言うんだよ！？","ENG":"What am I guilty of, huh? What?!!","TWN":"我為什麼需要自首？我又沒做什麼！！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……오라버니, 곧 감찰과가 여기로 들이닥칠 거예요. 도망치셔도 소용없어요.","JPN":"……お兄様、もうすぐ監察課がここに到着します。逃げても無駄ですよ。","ENG":"Jaehyuk... Investigations will be here shortly. You can’t run away.","TWN":"……大哥，監察科的人很快就會找到這裡，你是逃不掉的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"아, 그래? 참 좋은 소식 가져왔네?","JPN":"ああ、そうか？　それは嬉しい知らせじゃないか。","ENG":"Oh yeah? Well, thanks for the heads up.","TWN":"是嗎？那還真是個好消息呢！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"그 얘길 들었더니 아주 좋은 아이디어가 떠올랐거든.","JPN":"その話を聞いたら、とても良いアイデアが浮かんだぞ。","ENG":"That just gave me a great idea.","TWN":"聽你帶來這麼好的消息，我突然靈光乍現！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"실행범……. 이진 언니가 마주쳤던 사람이 당신이군요.","JPN":"実行犯……ホノカさんが出会った人はあなただったのですね。","ENG":"The killer... So it was you who Jin saw that night.","TWN":"真正的犯人……和李珍姐交手的人就是你吧！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"대체 당신은 누구죠? 왜 재혁 오라버니에게 협력하는 거죠?","JPN":"いったいあなたは誰ですか？　なぜにタツヤお兄様に協力するのですか？","ENG":"Who are you? Why are you helping him?","TWN":"你是誰？為什麼要幫大哥？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"크크큭……! 얘가 왜 협력하냐고?","JPN":"クククッ……！　こいつがなんで協力しているのかって？","ENG":"Kekeke...! Why’s she helping me?","TWN":"哼哼哼……！她為什麼要幫我？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"이건 네 생체 정보를 복제해 만든 짝퉁이거든. 내 명령이라면 죽을 수도 있는.","JPN":"これはお前の生体情報を複製して作った偽物だ。\\n俺の命令ならこの場で死ぬことすらできる。","ENG":"This is a copy of you made with your biometrics! I control her.","TWN":"她是利用你的生物資訊去製造出來的複製品，就算我叫她去死，她也會立刻乖乖去死！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"복제라고요……? 대체 누가 그런 짓을……?","JPN":"複製ですって……？　いったい誰がそんなことを……？","ENG":"A copy...? Who would do such a thing...?","TWN":"複製品……？是誰做的……？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"글쎄? 상품을 사용하는 소비자가 거기까지 알 필요 있냐?","JPN":"さあ？　商品を使う消費者がそこまで知る必要があるのか？","ENG":"Who knows. I don’t care about any of that.","TWN":"不知道，使用商品的消費者知道這麼多要幹嘛？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"그리고 지금은 다른 걸 걱정해야 할걸.","JPN":"それに今は他のことを心配するべきだろう。","ENG":"But I think there are other matters you should be worried about.","TWN":"而且你現在該擔心的不是這個吧？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"널 없애고 이 짝퉁한테 네 행세를 시키면……. 감찰과 놈들도 별 수 없겠지.","JPN":"お前を殺してこの偽物にお前の役をやらせれば……\\n監察課の連中も気づかないだろうな。","ENG":"If I get rid of you and order this knock-off to act like you... Then I’ll be able to fool Investigations too!","TWN":"只要把你除掉，再讓這個冒牌貨假裝成是你……監察科的人應該也分辨不出來吧？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그런 일이 가능하다고 생각하세요, 오라버니?","JPN":"そんなことができると思いますか、お兄様？","ENG":"Do you really think that’s possible, Jaehyuk?","TWN":"大哥覺得這是有可能的嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"도망칠 데도 없는데 마지막까지 발악해 봐야지!","JPN":"逃げ場もないんだ、最後まで足掻かないとな！","ENG":"I’ve got nothing to lose at this point!","TWN":"反正我也無處可逃，那還不如賭賭看！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"네 그 잘난 낯짝을 뭉개 버리는 장면을 볼 수 있다면 남는 장사기도 하고.","JPN":"お前のその偉そうなツラが潰れる瞬間が拝めるなら、\\nこっちも思い残すことはないさ。","ENG":"But if I go down with you, that’s not a bad deal on my part.","TWN":"要是能看到你那囂張的嘴臉被打爆，那我還算是有賺頭！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……알겠어요. 그러면 저 분을 제압한 다음 마저 듣기로 할게요.","JPN":"……わかりました。それでは、その方を制圧してから話を続けることにしましょう。","ENG":"...All right. Then we’ll talk after I deal with her.","TWN":"……好吧，那等我制伏她後，再請大哥跟我說吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저 분을 오라버니께 넘긴 사람에 대해서.","JPN":"その方をお兄様に渡した人について。","ENG":"About who gave her to you.","TWN":"到底是誰把她送給大哥的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};